import { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaArrowLeft, FaFileDownload, FaExternalLinkAlt } from 'react-icons/fa';
import Spinner from '../components/Spinner';
import schemeService from '../api/schemeService';

function SchemeDetail() {
  const [scheme, setScheme] = useState(null);
  const [loading, setLoading] = useState(true);
  const { id } = useParams();
  const navigate = useNavigate();

  useEffect(() => {
    const fetchScheme = async () => {
      try {
        const data = await schemeService.getSchemeById(id);
        setScheme(data);
      } catch (error) {
        toast.error('Error fetching scheme details');
        navigate('/schemes');
      } finally {
        setLoading(false);
      }
    };

    fetchScheme();
  }, [id, navigate]);

  if (loading) {
    return <Spinner />;
  }

  if (!scheme) {
    return (
      <div className="text-center py-10">
        <h2 className="text-2xl font-semibold mb-4">Scheme not found</h2>
        <Link
          to="/schemes"
          className="text-green-600 hover:text-green-800 font-medium"
        >
          Back to Schemes
        </Link>
      </div>
    );
  }

  return (
    <div>
      <div className="mb-6">
        <Link
          to="/schemes"
          className="text-green-600 hover:text-green-700 flex items-center"
        >
          <FaArrowLeft className="mr-2" /> Back to Schemes
        </Link>
      </div>

      <div className="bg-white rounded-lg shadow-md overflow-hidden">
        {scheme.imageUrl && (
          <div className="h-64 overflow-hidden">
            <img
              src={scheme.imageUrl}
              alt={scheme.name}
              className="w-full h-full object-cover"
            />
          </div>
        )}

        <div className="p-6">
          <h1 className="text-3xl font-bold text-green-700 mb-2">
            {scheme.name}
          </h1>
          <div className="flex flex-wrap gap-2 mb-4">
            <span className="bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded">
              {scheme.department}
            </span>
            <span className="bg-blue-100 text-blue-800 text-xs font-medium px-2.5 py-0.5 rounded">
              {scheme.status || 'Active'}
            </span>
          </div>

          <div className="grid md:grid-cols-2 gap-6 mb-6">
            <div>
              <h2 className="text-xl font-semibold text-gray-700 mb-2">
                Description
              </h2>
              <p className="text-gray-600 whitespace-pre-line">
                {scheme.description}
              </p>
            </div>

            <div>
              <h2 className="text-xl font-semibold text-gray-700 mb-2">
                Eligibility
              </h2>
              <p className="text-gray-600 whitespace-pre-line">
                {scheme.eligibility}
              </p>
            </div>
          </div>

          <div className="mb-6">
            <h2 className="text-xl font-semibold text-gray-700 mb-2">
              Benefits
            </h2>
            <p className="text-gray-600 whitespace-pre-line">
              {scheme.benefits}
            </p>
          </div>

          {scheme.applicationProcess && (
            <div className="mb-6">
              <h2 className="text-xl font-semibold text-gray-700 mb-2">
                Application Process
              </h2>
              <p className="text-gray-600 whitespace-pre-line">
                {scheme.applicationProcess}
              </p>
            </div>
          )}

          {scheme.documents && (
            <div className="mb-6">
              <h2 className="text-xl font-semibold text-gray-700 mb-2">
                Required Documents
              </h2>
              <p className="text-gray-600 whitespace-pre-line">
                {scheme.documents}
              </p>
            </div>
          )}

          {scheme.contactInfo && (
            <div className="mb-6">
              <h2 className="text-xl font-semibold text-gray-700 mb-2">
                Contact Information
              </h2>
              <p className="text-gray-600 whitespace-pre-line">
                {scheme.contactInfo}
              </p>
            </div>
          )}

          <div className="flex flex-wrap gap-4 mt-8">
            {scheme.applicationUrl && (
              <a
                href={scheme.applicationUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="btn btn-primary flex items-center"
              >
                <FaExternalLinkAlt className="mr-2" /> Apply Online
              </a>
            )}

            {scheme.documentUrl && (
              <a
                href={scheme.documentUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="btn btn-outline flex items-center"
              >
                <FaFileDownload className="mr-2" /> Download Guidelines
              </a>
            )}
          </div>
        </div>
      </div>

      {scheme.relatedSchemes && scheme.relatedSchemes.length > 0 && (
        <div className="mt-10">
          <h2 className="text-2xl font-semibold text-green-700 mb-4">
            Related Schemes
          </h2>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {scheme.relatedSchemes.map((relatedScheme) => (
              <div
                key={relatedScheme._id}
                className="bg-white rounded-lg shadow-md p-4 border-l-4 border-green-500"
              >
                <h3 className="text-lg font-semibold mb-2">
                  <Link
                    to={`/schemes/${relatedScheme._id}`}
                    className="text-green-600 hover:text-green-800"
                  >
                    {relatedScheme.name}
                  </Link>
                </h3>
                <p className="text-gray-600 text-sm line-clamp-2 mb-2">
                  {relatedScheme.description}
                </p>
                <span className="text-xs text-gray-500">
                  {relatedScheme.department}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

export default SchemeDetail;
